<meta name="color-scheme" content="dark">
<style id="global-dark-theme">
    :root{
        --page:#080f1d!important;--surface:#101a2c!important;--surface-2:#162238!important;
        --ink:#edf4ff!important;--muted:#94a3b8!important;--line:#26344b!important;
        --bs-body-bg:#080f1d;--bs-body-color:#edf4ff;--bs-border-color:#26344b;
        --bs-secondary-color:#94a3b8;--bs-tertiary-bg:#162238;--bs-emphasis-color:#fff;
    }
    html,body,.app,.main,.content,main{background-color:#080f1d!important;color:#edf4ff!important}
    body.bg-light,body.bg-gray-100,.bg-light,.bg-gray-100{background:#080f1d!important}
    .topbar,header.bg-white,.navbar.bg-light{background:rgba(12,21,37,.96)!important;border-color:#26344b!important;color:#edf4ff!important}
    .card,.panel,.metric,.metric-card,.news-card,.side-panel,.empty-state,.form-card,.main-card,
    .bg-white,.table,.table-responsive,.list-group-item,.modal-content,.dropdown-menu,.card-header,.card-footer{
        background-color:#101a2c!important;color:#edf4ff!important;border-color:#26344b!important
    }
    .bg-gray-50,.bg-gray-100,.weather-cell,.search-result:hover,.table-light,.input-group-text{background:#162238!important;color:#dbeafe!important}
    .bg-blue-50{background:#10284a!important;color:#bfdbfe!important}.bg-success-subtle{background:#103528!important}.bg-primary-subtle{background:#132e55!important}.bg-danger-subtle{background:#431c2a!important}.bg-info-subtle{background:#12364a!important}
    h1,h2,h3,h4,h5,h6,.h1,.h2,.h3,.h4,.h5,.h6,b,strong,.fw-bold,.font-bold,.font-semibold,.text-dark,.text-gray-800,.text-gray-900{color:#f8fbff!important}
    p,span,td,th,label,.form-label,.text-gray-600,.text-gray-500,.text-muted,small{border-color:#26344b}.text-muted,.text-gray-600,.text-gray-500,.text-gray-400{color:#94a3b8!important}
    a:not(.btn):not(.side-link):not(.navbar-brand):not(.brand){color:#7db5ff}a:not(.btn):hover{color:#acd0ff}
    .table{--bs-table-bg:#101a2c;--bs-table-color:#e7eefb;--bs-table-border-color:#26344b;--bs-table-hover-bg:#17243a;--bs-table-hover-color:#fff;--bs-table-striped-bg:#142035;--bs-table-striped-color:#e7eefb}
    .table thead th,.country-table th,thead.bg-gray-50{background:#162238!important;color:#a9b9cf!important;border-color:#30405a!important}
    tr,td,th,.divide-y>*{border-color:#26344b!important}
    input,select,textarea,.form-control,.form-select{background-color:#0b1424!important;color:#edf4ff!important;border-color:#33445e!important;color-scheme:dark}
    input::placeholder,textarea::placeholder{color:#72839b!important}.form-control:focus,.form-select:focus{background:#101b2f!important;color:#fff!important;border-color:#4f8ef7!important;box-shadow:0 0 0 .2rem #2563eb33!important}
    option{background:#101a2c;color:#fff}.btn-light{background:#1b2940!important;border-color:#30405a!important;color:#eaf2ff!important}.btn-outline-secondary{border-color:#53657f;color:#c3d0e2}.badge.text-bg-light{background:#26354d!important;color:#eaf2ff!important}
    .progress{background:#26344b!important}.border,.border-top,.border-bottom,.border-end,.border-start,.card{border-color:#26344b!important}.shadow,.shadow-sm,.shadow-md{box-shadow:0 10px 30px #0005!important}
    .control-panel,.map-panel,.map-legend,.temperature-scale,.leaflet-popup-content-wrapper,.leaflet-popup-tip{background:#101a2c!important;color:#edf4ff!important}.legend-item{color:#b7c4d8!important}.leaflet-control-layers,.leaflet-bar a{background:#101a2c!important;color:#fff!important;border-color:#33445e!important}
    .leaflet-tile-pane{filter:brightness(.72) invert(1) contrast(1.15) hue-rotate(180deg) saturate(.55)}
    .news-image,.popup-flag,.country-flag{filter:saturate(.92) brightness(.9)}
    canvas{color-scheme:dark}.chart-box,.chart-wrap{background:transparent!important}
    ::-webkit-scrollbar{width:10px;height:10px}::-webkit-scrollbar-track{background:#080f1d}::-webkit-scrollbar-thumb{background:#31415a;border-radius:10px;border:2px solid #080f1d}
    @media print{html,body,main,.card,.table{background:#fff!important;color:#111!important}h1,h2,h3,h4,h5,h6,b,strong,td,th,p,span,small{color:#111!important}}
</style>
<script>
    document.addEventListener('DOMContentLoaded',()=>{
        if(window.Chart){Chart.defaults.color='#a9b9cf';Chart.defaults.borderColor='#2b3a52'}
    });
</script>
